def run_srase(pack_id, persona):
    artifacts = load_pack(pack_id)
    scores = {}
    for wf in WORKFLOWS[persona]:
        scores[wf] = wf.score(artifacts)
    composite = weighted(scores)
    report = build_report(pack_id, persona, scores, composite)
    return sign_pades_sigstore_mldsa(report)

