export async function gienEmit(evt: GienEvent) {
  evt.sig = await signHybrid(evt);
  await gienClient.send({ topic: evt.type, messages: [{ key: evt.scope, value: JSON.stringify(evt) }] });
  await wormEmit('gien.out', { id: evt.id });
}
